from flask import Flask, request, jsonify
from flask import g
import jwt
import requests

app = Flask(__name__)

# Mock backend service URLs
BACKEND_SERVICES = {
    'service1': 'http://localhost:5001',
    'service2': 'http://localhost:5002'
}

def validate_token():
    auth_header = request.headers.get('Authorization')
    if not auth_header or not auth_header.startswith('Bearer '):
        return None
    
    token = auth_header.split(' ')[1]
    try:
        # In production, use verify=True and proper secret/key
        payload = jwt.decode(token, options={"verify_signature": False})
        return payload
    except jwt.InvalidTokenError:
        return None

@app.before_request
def authenticate():
    if request.endpoint and request.endpoint != 'health':
        payload = validate_token()
        if not payload:
            return jsonify({'error': 'Unauthorized'}), 401
        g.user_claims = payload

@app.route('/health')
def health():
    return jsonify({'status': 'healthy'})

@app.route('/service1/<path:subpath>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def service1_proxy(subpath):
    if not hasattr(g, 'user_claims'):
        return jsonify({'error': 'Unauthorized'}), 401
    
    backend_url = f"{BACKEND_SERVICES['service1']}/{subpath}"
    headers = {key: value for key, value in request.headers if key != 'Host'}
    headers['X-User-Claims'] = str(g.user_claims)
    
    try:
        response = requests.request(
            method=request.method,
            url=backend_url,
            headers=headers,
            data=request.get_data(),
            params=request.args
        )
        return response.content, response.status_code
    except Exception as e:
        return jsonify({'error': str(e)}), 500

